// Format RSS digest from unread entries only
const allEntries = $input.first().json.entries || [];
const entries = allEntries.filter(e => e.status === 'unread');
const today = new Date().toLocaleDateString('en-CA');

if (entries.length === 0) {
  return [{
    json: {
      markdown: `# Daily RSS Digest - ${today}\n\n**No unread articles today.**\n`,
      filename: `${today}.md`,
      entryIds: [],
      totalCount: 0
    }
  }];
}

// Group by category
const categories = {};
const starred = [];

for (const entry of entries) {
  const cat = entry.feed.category.title;
  if (!categories[cat]) categories[cat] = [];

  const plainText = (entry.content || '')
    .replace(/<[^>]*>/g, '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 200);

  const published = new Date(entry.published_at).toLocaleDateString('en-US', {
    month: 'short', day: 'numeric'
  });

  const item = {
    title: entry.title,
    url: entry.url,
    feed: entry.feed.title,
    published: published,
    preview: plainText,
    id: entry.id,
    starred: entry.starred
  };

  if (entry.starred) starred.push(item);
  categories[cat].push(item);
}

let md = `# Daily RSS Digest - ${today}\n\n`;
md += `**${entries.length} unread articles across ${Object.keys(categories).length} categories**\n\n`;

if (starred.length > 0) {
  md += `## Priority Reads\n\n`;
  for (const item of starred) {
    md += `- [${item.title}](${item.url}) - *${item.feed}*\n`;
  }
  md += `\n`;
}

const order = ['Industry News', 'Growth + Marketing', 'Product + Engineering', 'Business'];
const sortedCats = Object.keys(categories).sort((a, b) => {
  const ai = order.indexOf(a);
  const bi = order.indexOf(b);
  return (ai === -1 ? 99 : ai) - (bi === -1 ? 99 : bi);
});

for (const cat of sortedCats) {
  const items = categories[cat];
  md += `## ${cat} (${items.length})\n\n`;
  for (const item of items) {
    md += `- [${item.title}](${item.url}) - *${item.feed}* - ${item.published}\n`;
    md += `  > ${item.preview}...\n\n`;
  }
}

const entryIds = entries.map(e => e.id);

// Build category summary for Slack
const catSummary = {};
for (const cat of sortedCats) {
  catSummary[cat] = categories[cat].length;
}

return [{
  json: {
    markdown: md,
    filename: `${today}.md`,
    entryIds: entryIds,
    totalCount: entries.length,
    catSummary: catSummary,
    starred: starred,
    articlesByCategory: categories
  }
}];

const { markdown, filename } = $input.first().json;
const fs = require('fs');
const dir = '/home/node/your-vault/01-Inbox/daily-rss-digest';
const path = dir + '/' + filename;

if (!fs.existsSync(dir)) {
  fs.mkdirSync(dir, { recursive: true });
}

fs.writeFileSync(path, markdown, 'utf8');

return [{
  json: {
    ...$input.first().json,
    savedTo: path,
    success: true
  }
}];

// Load 7-day history from JSON files
const fs = require('fs');
const historyDir = '/home/node/your-vault/01-Inbox/content-signals/history';
const entries = $input.first().json.entries || [];

if (!fs.existsSync(historyDir)) {
  fs.mkdirSync(historyDir, { recursive: true });
}

const now = new Date();
const history = [];
let daysWithData = 0;

for (let i = 1; i <= 14; i++) {
  const d = new Date(now);
  d.setDate(d.getDate() - i);
  const dateStr = d.toLocaleDateString('en-CA');
  const filePath = `${historyDir}/${dateStr}-topics.json`;
  try {
    if (fs.existsSync(filePath)) {
      const data = JSON.parse(fs.readFileSync(filePath, 'utf8'));
      if (i <= 7) {
        history.push(data);
        daysWithData++;
      }
    }
  } catch (e) {}
}

// Prune files older than 14 days
try {
  const files = fs.readdirSync(historyDir);
  for (const file of files) {
    if (!file.endsWith('-topics.json')) continue;
    const dateMatch = file.match(/^(\d{4}-\d{2}-\d{2})/);
    if (dateMatch) {
      const fileDate = new Date(dateMatch[1]);
      const daysDiff = (now - fileDate) / (1000 * 60 * 60 * 24);
      if (daysDiff > 14) {
        fs.unlinkSync(`${historyDir}/${file}`);
      }
    }
  }
} catch (e) {}

return [{
  json: {
    entries,
    history,
    daysWithData,
    coldStart: daysWithData < 7
  }
}];

// Extract topics with pillar relevance filtering + topic clustering
// v2: Filters for Your Name's content pillars, clusters overlapping n-grams
const { entries, history, daysWithData, coldStart } = $input.first().json;

// ============================================================
// CONTENT PILLARS — topics must match ≥1 pillar to become signals
// ============================================================
const CONTENT_PILLARS = {
  'AI & Automation': {
    terms: [
      'ai','ai agent','ai agents','agentic','llm','large language model',
      'claude','openai','anthropic','gemini','perplexity','mistral',
      'model context protocol','mcp','multi-agent','workflow automation',
      'n8n','zapier','ai tool','ai tools','copilot','prompt engineering',
      'rag','vector database','embedding','ai infrastructure','vibe coding',
      'cursor','windsurf','claude code','chatgpt','ai marketing',
      'ai commerce','generative ai','gen ai','machine learning',
      'deep learning','chatbot','ai assistant','ai workflow','ai automation',
      'ai search','ai shopping','agentic commerce','coding assistant',
      'ai coding','artificial intelligence','computer vision','nlp',
      'transformer','diffusion','ai strategy','ai adoption','ai ops',
      'ai productivity','ai developer','ai platform'
    ],
    pillar: 'Pillar One'
  },
  'E-Commerce & DTC': {
    terms: [
      'ecommerce','e-commerce','shopify','shopify plus','dtc',
      'direct-to-consumer','d2c','marketplace','amazon','walmart connect',
      'conversion rate','aov','average order value','cart abandonment',
      'checkout','product page','fulfillment','unit economics',
      'customer acquisition cost','cac','ltv','lifetime value','arpu',
      'omnichannel','headless commerce','composable commerce',
      'tiktok shop','social commerce','subscription commerce',
      'bigcommerce','woocommerce','magento','product feed',
      'merchandising','pricing strategy','dropship','wholesale',
      'b2b commerce','live shopping','commerce platform','online store',
      'product discovery','shopping experience','order management'
    ],
    pillar: 'E-Commerce Strategy'
  },
  'Marketing & Growth': {
    terms: [
      'klaviyo','email marketing','lifecycle marketing','retention marketing',
      'crm','customer retention','churn','segmentation','personalization',
      'attribution','roas','return on ad spend','cpa','cost per acquisition',
      'performance marketing','paid media','google ads','meta ads',
      'facebook ads','seo','retail media','retail media network','rmn',
      'programmatic','cro','conversion optimization','analytics','ga4',
      'first-party data','zero party data','cookieless','marketing ops',
      'martech','marketing automation','cdp','customer data platform',
      'incrementality','media mix','marketing measurement','demand gen',
      'growth marketing','brand marketing','content marketing',
      'influencer marketing','affiliate marketing','marketing budget',
      'marketing roi','marketing leader','marketing strategy',
      'paid social','paid search','marketing spend','ad spend',
      'creative strategy','marketing analytics','marketing team'
    ],
    pillar: 'E-Commerce Strategy'
  },
  'Leadership & Career': {
    terms: [
      'hiring','layoffs','org design','org chart','vp marketing',
      'cmo','chief marketing officer','marketing leadership','management',
      'fractional','consulting','remote work','return to office','rto',
      'hybrid work','salary','compensation','job market','career',
      'title inflation','marketing team','marketing org','team structure',
      'culture','burnout','talent','recruiting','marketing leader',
      'executive','workforce','upskilling','reskilling','job search',
      'interview','resume','networking','promotion','career growth',
      'work-life balance','quiet quitting','great resignation'
    ],
    pillar: 'Pillar Three'
  }
};

// Build term → pillar(s) lookup, sorted longest-first for matching
const termToPillars = {};
for (const [name, config] of Object.entries(CONTENT_PILLARS)) {
  for (const term of config.terms) {
    const t = term.toLowerCase();
    if (!termToPillars[t]) termToPillars[t] = [];
    if (!termToPillars[t].includes(name)) termToPillars[t].push(name);
  }
}
const allTermsSorted = Object.keys(termToPillars).sort((a, b) => b.length - a.length);

function scorePillarRelevance(text) {
  const lower = text.toLowerCase();
  const matched = {};
  for (const term of allTermsSorted) {
    let found = false;
    if (term.length <= 4) {
      // Short terms: require word boundary to avoid false positives
      // e.g. "rag" should not match "leverages", "cro" should not match "cross"
      const re = new RegExp('\\b' + term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'i');
      found = re.test(lower);
    } else {
      found = lower.includes(term);
    }
    if (found) {
      for (const pillar of termToPillars[term]) {
        if (!matched[pillar]) matched[pillar] = [];
        if (!matched[pillar].includes(term)) matched[pillar].push(term);
      }
    }
  }
  return matched;
}

// ============================================================
// Stopwords + noise (expanded)
// ============================================================
const stopwords = new Set([
  'a','about','above','after','again','against','all','am','an','and','any','are',
  "aren't",'as','at','be','because','been','before','being','below','between','both',
  'but','by',"can't",'cannot','could',"couldn't",'did',"didn't",'do','does',"doesn't",
  'doing',"don't",'down','during','each','few','for','from','further','get','gets',
  'got','had',"hadn't",'has',"hasn't",'have',"haven't",'having','he',"he'd","he'll",
  "he's",'her','here',"here's",'hers','herself','him','himself','his','how',"how's",
  'i',"i'd","i'll","i'm","i've",'if','in','into','is',"isn't",'it',"it's",'its',
  'itself','just',"let's",'me','might','more','most',"mustn't",'my','myself','new',
  'no','nor','not','now','of','off','on','once','one','only','or','other','ought',
  'our','ours','ourselves','out','over','own','re','same','say','says',"shan't",
  'she',"she'd","she'll","she's",'should',"shouldn't",'so','some','still','such',
  'take','than','that',"that's",'the','their','theirs','them','themselves','then',
  'there',"there's",'these','they',"they'd","they'll","they're","they've",'this',
  'those','through','to','too','under','until','up','us','use','very','want','was',
  "wasn't",'we',"we'd","we'll","we're","we've",'were',"weren't",'what',"what's",
  'when',"when's",'where',"where's",'which','while','who',"who's",'whom','why',
  "why's",'will','with',"won't",'would',"wouldn't",'you',"you'd","you'll","you're",
  "you've",'your','yours','yourself','yourselves',
  'also','even','well','back','way','much','many','like','already',
  'around','another','come','first','find','go','going','good','great','help',
  'keep','know','last','let','long','look','made','make','may','need','never',
  'next','old','part','people','put','read','right','see','set','show','small',
  'start','tell','thing','think','three','time','try','turn','two','used','using',
  'via','week','work','world','year','years','really','actually','getting',
  'thought','things','something','everything','nothing','every','someone',
  'anyone','everyone','guys','hey','oh','yeah','nope','okay',
  'please','thanks','thank','sorry','sure','maybe','probably','definitely',
  'basically','literally','honestly','apparently','obviously','seriously'
]);

const noiseWords = new Set([
  'marketing','digital','business','online','brand','brands','content','strategy',
  'data','customer','customers','company','companies','market','markets','growth',
  'team','teams','product','products','service','services','industry','platform',
  'technology','tech','report','reports','update','updates','news','latest','top',
  'best','guide','trends','future','key','big','based','level','high','today',
  'review','podcast','episode','article','post','blog','newsletter','weekly',
  'daily','monthly','opinion','analysis','insight','insights','research','study',
  'series','feature','features','announces','announced','launch','launches',
  'launched','released','introducing','promote','looking','else','does','fun',
  'free','question','thoughts','experience','advice','recommend','recommendation',
  'suggestions','wondering','curious','feel','believe','tried','check','share',
  'join','follow','subscribe','click','learn','watch','watching','video','photo',
  'picture','image','meme','funny','love','hate','amazing','awesome','terrible',
  'horrible','perfect','worst','game','super','bowl','ad','ads','commercial',
  'vote','voting','election'
]);


// ============================================================
// GENERIC BIGRAMS — too common to be meaningful signals
// These appear across unrelated articles and cause false convergence
// ============================================================
const GENERIC_BIGRAMS = new Set([
  'open source','last year','next year','last week','next week',
  'real time','real-time','long term','long-term','short term',
  'end-to-end','day-to-day','year-over-year','month-over-month',
  'full time','full-time','part time','part-time',
  'third party','third-party','first party','first-party',
  'small business','large scale','large-scale',
  'case study','case studies','white paper',
  'best practices','thought leadership',
  'supply chain','value proposition',
  'competitive advantage','market share',
  'bottom line','top line','year old',
]);

const redditNoise = [/\[i will not promote\]/gi, /\[just for fun\]/gi, /\[unpopular opinion\]/gi];

function cleanWord(w) {
  return w.replace(/[^a-zA-Z0-9'-]/g, '').toLowerCase();
}

function isUseful(word) {
  if (word.length < 3) return false;
  if (stopwords.has(word)) return false;
  if (noiseWords.has(word)) return false;
  if (/^\d+$/.test(word)) return false;
  return true;
}

function extractNgrams(title) {
  let cleaned = title;
  for (const pat of redditNoise) cleaned = cleaned.replace(pat, '');
  const words = cleaned.split(/\s+/).map(w => cleanWord(w)).filter(w => w.length > 0);
  const ngrams = [];

  for (let i = 0; i < words.length - 1; i++) {
    const w1 = words[i], w2 = words[i+1];
    if (isUseful(w1) && isUseful(w2)) {
      const bigram = w1 + ' ' + w2;
      if (!GENERIC_BIGRAMS.has(bigram)) {
        ngrams.push(bigram);
      }
    }
  }

  for (let i = 0; i < words.length - 2; i++) {
    const w1 = words[i], w2 = words[i+1], w3 = words[i+2];
    const useful = [w1,w2,w3].filter(w => isUseful(w)).length;
    if (useful >= 2 && w1.length >= 3 && w2.length >= 3 && w3.length >= 3) {
      ngrams.push(w1 + ' ' + w2 + ' ' + w3);
    }
  }

  return ngrams;
}

// ============================================================
// Build topic map with pillar relevance
// ============================================================
const topicMap = {};

for (const entry of entries) {
  const category = entry.feed?.category?.title || 'Unknown';
  const feed = entry.feed?.title || 'Unknown';
  const title = entry.title || '';
  const articlePillars = scorePillarRelevance(title);

  const ngrams = extractNgrams(title);
  const seen = new Set();

  for (const ng of ngrams) {
    if (seen.has(ng)) continue;
    seen.add(ng);

    if (!topicMap[ng]) {
      topicMap[ng] = { count: 0, categories: [], feeds: [], articles: [], _pillarSets: {} };
    }
    topicMap[ng].count++;
    if (!topicMap[ng].categories.includes(category)) topicMap[ng].categories.push(category);
    if (!topicMap[ng].feeds.includes(feed)) topicMap[ng].feeds.push(feed);
    topicMap[ng].articles.push({
      title, url: entry.url, feed, category,
      published: entry.published_at,
      isReddit: (entry.url || '').includes('reddit.com'),
      pillars: articlePillars
    });

    for (const [pillar, terms] of Object.entries(articlePillars)) {
      if (!topicMap[ng]._pillarSets[pillar]) topicMap[ng]._pillarSets[pillar] = new Set();
      for (const t of terms) topicMap[ng]._pillarSets[pillar].add(t);
    }
  }
}

// Also check if the topic text itself matches pillars
for (const [topic, data] of Object.entries(topicMap)) {
  const topicPillars = scorePillarRelevance(topic);
  for (const [pillar, terms] of Object.entries(topicPillars)) {
    if (!data._pillarSets[pillar]) data._pillarSets[pillar] = new Set();
    for (const t of terms) data._pillarSets[pillar].add(t);
  }
  // Convert Sets → arrays for JSON
  data.pillarMatches = {};
  for (const [p, s] of Object.entries(data._pillarSets)) {
    data.pillarMatches[p] = [...s];
  }
  delete data._pillarSets;
}

// ============================================================
// Cluster overlapping topics (>60% shared source articles)
// ============================================================
const topicEntries = Object.entries(topicMap).filter(([_, d]) => d.count >= 2);
const clusters = [];
const assigned = new Set();

for (const [topic, data] of topicEntries) {
  if (assigned.has(topic)) continue;

  const cluster = { label: topic, members: [topic], data: JSON.parse(JSON.stringify(data)) };
  assigned.add(topic);
  const clusterUrls = new Set(data.articles.map(a => a.url));

  for (const [other, otherData] of topicEntries) {
    if (assigned.has(other)) continue;
    const otherUrls = new Set(otherData.articles.map(a => a.url));
    const intersection = [...clusterUrls].filter(u => otherUrls.has(u)).length;
    const smaller = Math.min(clusterUrls.size, otherUrls.size);

    if (smaller > 0 && intersection / smaller >= 0.6) {
      cluster.members.push(other);
      assigned.add(other);
      // Merge articles, categories, feeds, pillars
      for (const a of otherData.articles) {
        if (!clusterUrls.has(a.url)) {
          cluster.data.articles.push(a);
          clusterUrls.add(a.url);
        }
      }
      cluster.data.count = Math.max(cluster.data.count, otherData.count);
      for (const cat of otherData.categories) {
        if (!cluster.data.categories.includes(cat)) cluster.data.categories.push(cat);
      }
      for (const f of otherData.feeds) {
        if (!cluster.data.feeds.includes(f)) cluster.data.feeds.push(f);
      }
      for (const [p, terms] of Object.entries(otherData.pillarMatches || {})) {
        if (!cluster.data.pillarMatches[p]) cluster.data.pillarMatches[p] = [];
        const existing = new Set(cluster.data.pillarMatches[p]);
        for (const t of terms) if (!existing.has(t)) cluster.data.pillarMatches[p].push(t);
      }
    }
  }

  // Pick best label: prefer longest pillar-relevant topic
  const relevant = cluster.members.filter(t => {
    const tm = topicMap[t];
    return tm && Object.keys(tm.pillarMatches || {}).length > 0;
  });
  if (relevant.length > 0) {
    cluster.label = relevant.sort((a, b) => b.length - a.length)[0];
  } else {
    cluster.label = cluster.members.sort((a, b) => b.length - a.length)[0];
  }

  clusters.push(cluster);
}

// Build final clustered topic map
const clusteredTopicMap = {};
for (const c of clusters) {
  const hasPillar = Object.keys(c.data.pillarMatches || {}).length > 0;
  clusteredTopicMap[c.label] = {
    ...c.data,
    clusteredFrom: c.members,
    hasPillarRelevance: hasPillar,
    matchedPillars: Object.keys(c.data.pillarMatches || {})
  };
}

// ============================================================
// Historical baselines
// ============================================================
const historicalTopics = {};
for (const dayData of history) {
  for (const [topic, count] of Object.entries(dayData.topics || {})) {
    if (!historicalTopics[topic]) historicalTopics[topic] = [];
    historicalTopics[topic].push(count);
  }
}
const baselines = {};
for (const [topic, counts] of Object.entries(historicalTopics)) {
  const avg = counts.reduce((a,b) => a+b, 0) / Math.max(counts.length, 1);
  baselines[topic] = { avg: Math.round(avg * 100) / 100, days: counts.length };
}

const todayTopics = {};
for (const [topic, data] of Object.entries(clusteredTopicMap)) {
  todayTopics[topic] = data.count;
}

return [{
  json: {
    topicMap: clusteredTopicMap,
    baselines,
    todayTopics,
    coldStart,
    daysWithData,
    totalArticles: entries.length,
    totalCategories: [...new Set(entries.map(e => e.feed?.category?.title))].length,
    entries,
    pillarConfig: CONTENT_PILLARS
  }
}];

// Detect signals: pillar-filtered convergence + volume spikes
// v2: Topics must match ≥1 content pillar to become a signal
const { topicMap, baselines, todayTopics, coldStart, daysWithData, totalArticles, totalCategories, entries, pillarConfig } = $input.first().json;

const signals = [];

for (const [topic, data] of Object.entries(topicMap)) {
  if (data.count < 2) continue;

  // ===== PILLAR GATE: skip topics with no pillar relevance =====
  if (!data.hasPillarRelevance) continue;

  const uniqueCategories = data.categories.length;
  const uniqueFeeds = data.feeds.length;
  const baseline = baselines[topic];

  let signalTypes = [];
  let strength = 'Low';
  let isSignal = false;
  let baselineAvg = baseline ? baseline.avg : 0;
  let volumeChange = 0;

  // Cross-source convergence — require TOPICAL overlap, not just keyword match
  // Articles must share pillar-level context, not just contain the same n-gram
  const articlePillarSets = data.articles.map(a => new Set(Object.keys(a.pillars || {})));
  let sharedPillarCount = 0;
  if (articlePillarSets.length >= 2) {
    // Check if articles share at least one pillar (beyond just the n-gram keyword)
    const allPillars = articlePillarSets.reduce((union, s) => {
      for (const p of s) union.add(p);
      return union;
    }, new Set());
    for (const p of allPillars) {
      const articlesWithPillar = articlePillarSets.filter(s => s.has(p)).length;
      if (articlesWithPillar >= 2) sharedPillarCount++;
    }
  }

  // Convergence tiers:
  // Tier 1 (High): 3+ categories OR 5+ mentions
  // Tier 2 (Medium): 2+ categories with shared pillar context OR 3+ feeds
  // Tier 3 (Low): pillar-matched topic with 2+ mentions from any source mix
  if (uniqueCategories >= 3 || data.count >= 5) {
    signalTypes.push('cross-source convergence');
    isSignal = true;
    strength = 'High';
  } else if (uniqueCategories >= 2 && (data.count >= 3 || sharedPillarCount > 0)) {
    signalTypes.push('cross-source convergence');
    isSignal = true;
    strength = 'Medium';
  } else if (uniqueFeeds >= 3 && data.count >= 3) {
    signalTypes.push('cross-source convergence');
    isSignal = true;
    strength = 'Medium';
  } else if (data.count >= 2 && Object.keys(data.pillarMatches || {}).length > 0) {
    // Pillar-relevant topic with 2+ mentions - low-confidence but worth tracking
    signalTypes.push('pillar-relevant mention');
    isSignal = true;
    strength = 'Low';
  }

  // Volume spike
  if (baseline && baseline.avg > 0) {
    volumeChange = Math.round(((data.count - baseline.avg) / baseline.avg) * 100);
    if (data.count > 2 * baseline.avg) {
      signalTypes.push('volume spike');
      isSignal = true;
      if (strength === 'Low') strength = 'Medium';
      if (data.count > 3 * baseline.avg) strength = 'High';
    }
  } else if (coldStart && data.count >= 3) {
    signalTypes.push('emerging (new topic)');
    isSignal = true;
    if (strength === 'Low') strength = 'Medium';
  }

  // Reddit presence
  const redditArticles = data.articles.filter(a => a.isReddit);
  data.hasReddit = redditArticles.length > 0;

  if (!isSignal) continue;

  // Map to LinkedIn content pillar
  const matchedPillars = data.matchedPillars || [];
  let contentSuggestion = 'Twitter thread';

  if (matchedPillars.includes('AI & Automation')) {
    contentSuggestion = data.count >= 4 ? 'Essay (Substack)' : 'LinkedIn post (Builder)';
  } else if (matchedPillars.includes('E-Commerce & DTC') || matchedPillars.includes('Marketing & Growth')) {
    contentSuggestion = data.count >= 4 ? 'Essay (Substack)' : 'LinkedIn post (Strategy)';
  } else if (matchedPillars.includes('Leadership & Career')) {
    contentSuggestion = 'LinkedIn post (Career)';
  }

  // Build rationale with pillar context
  const pillarNames = matchedPillars
    .map(p => (pillarConfig && pillarConfig[p]) ? pillarConfig[p].pillar : p)
    .join(', ');

  let rationale = `Relevant to: ${pillarNames}.`;
  if (signalTypes.includes('cross-source convergence')) {
    rationale += ` Appearing across ${uniqueCategories} categories and ${uniqueFeeds} feeds.`;
  }
  if (signalTypes.includes('volume spike')) {
    rationale += ` Volume ${volumeChange > 0 ? '+' : ''}${volumeChange}% vs 7-day average.`;
  }
  if (signalTypes.includes('emerging (new topic)')) {
    rationale += ` Emerging with ${data.count} mentions today.`;
  }

  signals.push({
    topic, strength, types: signalTypes,
    categories: data.categories, feeds: data.feeds,
    count: data.count, baselineAvg, volumeChange,
    articles: data.articles,
    hasReddit: data.hasReddit || false,
    contentSuggestion,
    rationale: rationale.trim(),
    matchedPillars,
    pillarMatches: data.pillarMatches || {},
    clusteredFrom: data.clusteredFrom || [topic]
  });
}

const strengthOrder = { 'High': 0, 'Medium': 1, 'Low': 2 };
signals.sort((a, b) => {
  if (strengthOrder[a.strength] !== strengthOrder[b.strength]) {
    return strengthOrder[a.strength] - strengthOrder[b.strength];
  }
  return b.count - a.count;
});

