    signals, topicList, topicMap, todayTopics, baselines,
    coldStart, daysWithData, totalArticles, totalCategories,
    entries, pillarConfig
  }
}];

// Extract Reddit URLs from signals for HTTP Request node
// v2: Uses URL-keyed mapping instead of index-based for robustness
