}

const toFetch = redditUrls.slice(0, 10);

// Store URL mapping keyed by jsonUrl for reliable merge
const staticData = $getWorkflowStaticData('global');
staticData._redditUrlMap = {};
for (const u of toFetch) {
  staticData._redditUrlMap[u.jsonUrl] = u.originalUrl;
}

if (toFetch.length === 0) {
  return [{ json: { _noReddit: true } }];
}

return toFetch.map(item => ({
  json: { jsonUrl: item.jsonUrl, _noReddit: false, _originalUrl: item.originalUrl }
}));

// Merge Reddit engagement data back into signals
// v2: URL-keyed lookup (not index-based) for reliability
const originalData = $('Detect Signals').first().json;
const { signals } = originalData;
const items = $input.all();
const redditData = {};

// Get URL mapping from static data
const staticData = $getWorkflowStaticData('global');
const urlMap = staticData._redditUrlMap || {};
delete staticData._redditUrlMap;

for (let i = 0; i < items.length; i++) {
  if (items[i].json._noReddit) continue;

  // Try to find original URL: first from static map, then from item metadata
  let originalUrl = null;
  const itemJson = items[i].json;

  // The HTTP Request node may have replaced the JSON, so check static map by index fallback
  // But prefer URL-keyed lookup if we can identify which request this was
  if (itemJson._originalUrl) {
    originalUrl = itemJson._originalUrl;
  } else {
    // Fallback: try index-based from the URL map values
    const mapValues = Object.values(urlMap);
    if (i < mapValues.length) originalUrl = mapValues[i];
  }

  if (!originalUrl) continue;

  try {
    const json = itemJson;
    const listing = Array.isArray(json) ? json : null;
    if (listing && listing[0]?.data?.children?.[0]?.data) {
      const post = listing[0].data.children[0].data;
      redditData[originalUrl] = {
        score: post.score || 0,
        comments: post.num_comments || 0,
        upvoteRatio: post.upvote_ratio || 0,
        highEngagement: (post.num_comments >= 50 || post.score >= 100)
      };
    }
  } catch (e) {}
}

for (const signal of signals) {
  let hasHighEngagement = false;
  for (const article of signal.articles) {
    if (article.isReddit && redditData[article.url]) {
      const rd = redditData[article.url];
      article.redditScore = rd.score;
      article.redditComments = rd.comments;
      article.redditUpvoteRatio = rd.upvoteRatio;
      article.highEngagement = rd.highEngagement;
      if (rd.highEngagement) hasHighEngagement = true;
    }
  }
  if (hasHighEngagement) {
    if (!signal.types.includes('Reddit engagement')) {
      signal.types.push('Reddit engagement');
    }
    if (signal.strength === 'Low') signal.strength = 'Medium';
    signal.rationale += ' High Reddit engagement signals strong community interest.';
  }
}

return [{ json: { ...originalData, signals, redditData } }];

// Score signal impact with pillar relevance factor
// v2: Replaces broken recency factor with pillar relevance (2x weight)
const data = $input.first().json;
const { signals, totalCategories } = data;

for (const signal of signals) {
  // Factor 1: Source Diversity (0-10, weight 1.5x) — max 15
  const diversityRaw = (signal.categories.length / Math.max(totalCategories, 1)) * 10;
  const diversity = Math.min(Math.round(diversityRaw * 100) / 100, 10);

  // Factor 2: Volume vs Baseline (0-10, weight 1x) — max 10
  let volume = 0;
  if (signal.baselineAvg > 0) {
    volume = Math.min((signal.count / signal.baselineAvg), 10);
  } else {
    volume = Math.min(signal.count * 2, 10);
  }
  volume = Math.round(volume * 100) / 100;

  // Factor 3: Reddit Engagement (0-10, weight 0.5x) — max 5
  let reddit = 0;
  let maxRedditComments = 0;
  let maxRedditUpvotes = 0;
  for (const article of signal.articles) {
    if (article.redditComments !== undefined) {
      maxRedditComments = Math.max(maxRedditComments, article.redditComments);
    }
    if (article.redditScore !== undefined) {
      maxRedditUpvotes = Math.max(maxRedditUpvotes, article.redditScore);
    }
  }
  reddit = Math.round((Math.min(maxRedditComments / 100, 1) * 5 + Math.min(maxRedditUpvotes / 100, 1) * 5) * 100) / 100;

  // Factor 4: Pillar Relevance (0-10, weight 2x) — max 20
  // More pillars matched + more terms matched = higher relevance
  const pillarCount = (signal.matchedPillars || []).length;
  const termCount = Object.values(signal.pillarMatches || {})
    .reduce((sum, terms) => sum + (Array.isArray(terms) ? terms.length : 0), 0);
  const pillarScore = Math.min(pillarCount * 3, 6);    // 1 pillar=3, 2+=6
  const termScore = Math.min(termCount * 0.8, 4);      // more term matches = higher
  const relevance = Math.min(Math.round((pillarScore + termScore) * 100) / 100, 10);

  // Weighted impact score (max: 15 + 10 + 5 + 20 = 50)
  const impactScore = Math.round(
    ((diversity * 1.5) + (volume * 1) + (reddit * 0.5) + (relevance * 2)) * 100
  ) / 100;

  signal.impactScore = impactScore;
  signal.scoreBreakdown = {
    diversity: { raw: diversity, weighted: Math.round(diversity * 1.5 * 100) / 100 },
    volume: { raw: volume, weighted: Math.round(volume * 1 * 100) / 100 },
    reddit: { raw: reddit, weighted: Math.round(reddit * 0.5 * 100) / 100 },
    relevance: { raw: relevance, weighted: Math.round(relevance * 2 * 100) / 100 }
  };
}

signals.sort((a, b) => b.impactScore - a.impactScore);

return [{ json: { ...data, signals } }];

