// Content pillar terms for pre-filtering
const PILLAR_TERMS = {
  'AI & Automation': ['ai', 'agent', 'automation', 'llm', 'claude', 'chatgpt', 'openai', 'anthropic', 'gemini', 'copilot', 'machine learning', 'mcp', 'workflow', 'pipeline', 'n8n', 'generative', 'agentic'],
  'E-Commerce & DTC': ['shopify', 'dtc', 'ecommerce', 'e-commerce', 'marketplace', 'amazon', 'retail', 'conversion', 'checkout', 'fulfillment', 'commerce', 'subscription', 'wholesale'],
  'Marketing & Growth': ['klaviyo', 'email marketing', 'lifecycle', 'retention', 'seo', 'analytics', 'attribution', 'cro', 'personalization', 'paid media', 'performance marketing', 'martech', 'campaign'],
  'Leadership & Career': ['hiring', 'layoff', 'org design', 'leadership', 'career', 'compensation', 'management', 'restructuring', 'marketing leader', 'cmo', 'vp marketing']
};

// Pre-filter: articles with ANY pillar keyword in title
const candidates = [];
for (const article of articles) {
  const title = (article.title || '').toLowerCase();
  const matchedPillars = [];
  for (const [pillar, terms] of Object.entries(PILLAR_TERMS)) {
    for (const term of terms) {
      if (term.length <= 3) {
        const re = new RegExp('\\b' + term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'i');
        if (re.test(title)) { matchedPillars.push(pillar); break; }
      } else {
        if (title.includes(term)) { matchedPillars.push(pillar); break; }
      }
    }
  }
  if (matchedPillars.length > 0) {
    candidates.push({
      title: article.title,
      url: article.url,
      feed: article.feed?.title || 'unknown',
      pillars: [...new Set(matchedPillars)],
      summary: (article.content || '').replace(/<[^>]*>/g, '').substring(0, 200).trim()
    });
  }
}

if (candidates.length === 0) {
  return [{ json: { _scoutSkipped: true, _scoutReason: 'no pillar-relevant articles' } }];
}

// Send up to 25 candidates to Gemini
const toScore = candidates.slice(0, 25);

