cutoff.setDate(cutoff.getDate() - 14);
const cutoffStr = cutoff.toLocaleDateString('en-CA');
existingSeeds = existingSeeds.filter(s => s.date >= cutoffStr);

// Parse Gemini response
let newSeeds = [];
try {
  const candidates = geminiInput.candidates || [];
  if (candidates.length > 0 && candidates[0].content?.parts?.[0]?.text) {
    const text = candidates[0].content.parts[0].text;
    const parsed = JSON.parse(text);
    const rawSeeds = parsed.seeds || [];

    // Map article numbers back to actual article data
    const candidateArticles = prepData._candidates || [];
    for (const seed of rawSeeds) {
      const idx = (seed.article_number || 0) - 1;
      if (idx >= 0 && idx < candidateArticles.length) {
        const article = candidateArticles[idx];
        newSeeds.push({
          date: today,
          title: article.title,
          url: article.url,
          feed: article.feed,
          pillar: seed.pillar || article.pillars[0],
          seedScore: seed.seed_score,
          narrativeTag: seed.narrative_tag || '',
          rationale: seed.seed_rationale || '',
          storyAngle: seed.story_angle || '',
