if (allSeeds.length > 0) {
  md += `## All Active Seeds by Theme\n\n`;
  const byTag = {};
  for (const s of allSeeds) {
    const tag = s.narrativeTag || 'uncategorized';
    if (!byTag[tag]) byTag[tag] = [];
    byTag[tag].push(s);
  }
  const sortedTags = Object.entries(byTag).sort((a, b) => b[1].length - a[1].length);
  for (const [tag, seeds] of sortedTags) {
    md += `### ${tag} (${seeds.length})\n`;
    for (const s of seeds) {
      md += `- [${s.title}](${s.url}) — *${s.feed}* (${s.date}, score: ${s.seedScore}/10)\n`;
    }
    md += '\n';
  }
}

fs.writeFileSync(mdFile, md, 'utf8');

// ===== AUTO-GENERATE BRIEF STUBS FOR THREADS =====
const briefsDir = '/home/node/your-vault/01-Inbox/content-signals/briefs';
const threadBriefs = [];
for (const t of threads) {
  const slug = t.tag.replace(/[^a-z0-9]+/g, '-').substring(0, 50);
  const filename = `${today}-thread-${slug}.md`;
  const filepath = `${briefsDir}/${filename}`;

  // Don't overwrite if already generated today
  if (fs.existsSync(filepath)) continue;

  const articles = t.seeds.map(s =>
    `- [${s.title}](${s.url}) — *${s.feed}* (${s.date})\n  ${s.storyAngle}`
  ).join('\n');

  const brief = `---
signal_date: ${today}
topic: ${t.tag}
source: story-seeds
seed_count: ${t.seedCount}
days_tracked: ${t.days}
matched_pillars: [${t.pillar}]
enrichment: narrative-thread
status: stub
---

# Narrative Thread: ${t.tag}

## Thread Summary

This topic has accumulated **${t.seedCount} story seeds** over **${t.days} days** — enough signal for a content piece.

**Primary pillar:** ${t.pillar}

## Source Articles

${articles}

## Suggested Approach

This is a narrative thread, not a breaking signal. The angle should synthesize across sources — what pattern emerges when you read these together? What do these articles collectively reveal that none of them say individually?

## Usage

Run in Claude Code:
\`\`\`
/write-from-signal ${t.tag}
\`\`\`
`;
  fs.writeFileSync(filepath, brief, 'utf8');
  threadBriefs.push({ filename, tag: t.tag, seedCount: t.seedCount });
}

return [{ json: {
  scoutResult: 'success',
  newSeedsToday: genuinelyNew.length,
  totalActiveSeeds: allSeeds.length,
  narrativeThreads: threads.length,
  warmingThreads: warming.length,
  threadBriefsGenerated: threadBriefs,
  seedsFile: mdFile,
  dataFile
} }];

// Build rich Slack digest message with curated picks
const input = $input.first().json;
const today = new Date().toLocaleDateString('en-US', {
  month: 'short', day: 'numeric', timeZone: 'America/New_York'
});
const totalCount = input.totalCount || 0;
const catSummary = input.catSummary || {};
const starred = input.starred || [];
const articlesByCategory = input.articlesByCategory || {};
const catCount = Object.keys(catSummary).length;

// --- Header ---
let text = ':newspaper: *Daily Feed Intelligence \u2014 ' + today + '*\n';
text += totalCount + ' articles across ' + catCount + ' categories\n\n';

// --- Category breakdown ---
if (catCount > 0) {
  const catLine = Object.entries(catSummary)
    .map(([cat, count]) => cat + ' (' + count + ')')
    .join(' \u00b7 ');
  text += ':file_folder: ' + catLine + '\n\n';
}

// --- Curate top 5-8 picks ---
// Priority: starred first, then pick 1-2 from each category (skip Reddit noise)
const picks = [];
const seenUrls = new Set();

// 1. All starred articles first
for (const item of starred) {
  if (!seenUrls.has(item.url)) {
    picks.push({ ...item, reason: 'starred' });
    seenUrls.add(item.url);
  }
}

// 2. From each category, pick top articles (skip Reddit, prefer industry sources)
const skipCategories = new Set(['Reddit']);
const categoryOrder = ['Industry News', 'Growth + Marketing', 'AI + Technology', 'Product + Engineering', 'Business'];
const orderedCats = Object.keys(articlesByCategory).sort((a, b) => {
  const ai = categoryOrder.indexOf(a);
  const bi = categoryOrder.indexOf(b);
  return (ai === -1 ? 99 : ai) - (bi === -1 ? 99 : bi);
});

for (const cat of orderedCats) {
  if (skipCategories.has(cat)) continue;
  const items = articlesByCategory[cat] || [];
  let catPicks = 0;
  const maxPerCat = Math.max(1, Math.min(2, Math.ceil(8 / Math.max(catCount - 1, 1))));
  for (const item of items) {
    if (catPicks >= maxPerCat) break;
    if (picks.length >= 8) break;
    if (seenUrls.has(item.url)) continue;
    picks.push({ ...item, category: cat });
    seenUrls.add(item.url);
    catPicks++;
  }
}

// --- Format picks ---
if (picks.length > 0) {
  text += ':star: *Top Reads:*\n';
  for (const p of picks) {
    const cat = p.category || p.reason || '';
    const preview = (p.preview || '').substring(0, 120).replace(/\n/g, ' ');
    text += '\u2022 <' + p.url + '|' + p.title + '>';
    text += ' \u2014 _' + p.feed + '_';
    if (cat && cat !== 'starred') text += ' [' + cat + ']';
    text += '\n';
    if (preview) text += '  ' + preview + '\u2026\n';
  }
  text += '\n';
}

// --- Obsidian link to full digest ---
const digestPath = '01-Inbox/daily-rss-digest/' + input.filename;
const encodedPath = encodeURIComponent(digestPath).replace(/%2F/g, '/');
text += ':bookmark: <obsidian://open?vault=your-vault&file=' + encodedPath + '|Full digest in Obsidian>';

return [{ json: { text } }];

// Flag ExecPR Signals — detect PR-worthy opportunities from today's signals
// Writes JSON flags file for morning-pipeline.sh to process
const fs = require('fs');
const data = $input.first().json;
const { signals } = data;
const today = new Date().toLocaleDateString('en-CA');

const flagsDir = '/home/node/your-vault/01-Inbox/content-signals/execpr-flags';
if (!fs.existsSync(flagsDir)) {
  fs.mkdirSync(flagsDir, { recursive: true });
}

const EXECPR_KEYWORDS = [
  'podcast', 'award', 'conference', 'speaking', 'cfp',
  'byline', 'expert source', 'haro', 'call for speakers',
  'nominations', 'summit', 'keynote', 'panelist'
];

const flags = [];

for (const signal of signals) {
  const matchedPillars = signal.matchedPillars || [];
  const isLeadershipPillar = matchedPillars.includes('Leadership & Career');

  // Check article titles for ExecPR keywords
  const articles = signal.articles || [];
  const titleText = articles.map(a => (a.title || '').toLowerCase()).join(' ');
  const hasKeyword = EXECPR_KEYWORDS.some(kw => titleText.includes(kw));

  // High strategy fit + positioning alignment
  const highFit = (signal.strategyFit || 0) >= 8 && isLeadershipPillar;

  if (!isLeadershipPillar && !hasKeyword && !highFit) continue;

  // Determine opportunity type
  let type = 'content-signal';
  if (titleText.includes('podcast')) type = 'podcast';
  else if (titleText.includes('award') || titleText.includes('nominations')) type = 'award';
  else if (titleText.includes('conference') || titleText.includes('summit') || titleText.includes('cfp') || titleText.includes('call for speakers')) type = 'speaking';
  else if (titleText.includes('haro') || titleText.includes('expert source') || titleText.includes('byline')) type = 'press';

  flags.push({
    topic: signal.aiTopicName || signal.topic,
    type,
    strategy_fit: signal.strategyFit || null,
    articles: articles.slice(0, 5).map(a => ({
      title: a.title,
      url: a.url,
      feed: a.feed
    })),
    rationale: signal.fitRationale || signal.rationale || '',
    suggested_action: type === 'podcast' ? 'Review for /execpr:pitch podcast'
      : type === 'award' ? 'Review for /execpr:submit award'
      : type === 'speaking' ? 'Review for /execpr:submit speaking'
      : type === 'press' ? 'Review for /execpr:pitch press'
      : 'Review for /execpr:pitch or /execpr:submit'
  });
}

// Write flags file
const flagsFile = `${flagsDir}/${today}.json`;
fs.writeFileSync(flagsFile, JSON.stringify(flags, null, 2), 'utf8');

return [{ json: { ...data, execprFlags: flags, execprFlagCount: flags.length, execprFlagsFile: flagsFile } }];

// Auto-Assign Sprint — map briefs to pillars, calculate scheduled dates, assign sprint fields
// v2: Adds urgency tiers (routine / high-signal / breaking) with displacement detection
const fs = require('fs');
const data = $input.first().json;
const { generatedBriefs, briefsDir } = data;

if (!generatedBriefs || generatedBriefs.length === 0) {
  return [{ json: { ...data, sprintAssignments: [], sprintAssignedCount: 0, urgencyAlerts: [] } }];
}

// Load pillars config
const pillarsPath = '/home/node/your-vault/Repos.nosync/gcd/.planning/pillars.json';
let pillarsConfig;
try {
  pillarsConfig = JSON.parse(fs.readFileSync(pillarsPath, 'utf8'));
} catch (e) {
  return [{ json: { ...data, sprintAssignments: [], sprintAssignedCount: 0, urgencyAlerts: [], sprintError: 'Could not load pillars.json: ' + e.message } }];
}

const pillars = pillarsConfig.pillars;

const PILLAR_MAP = {
  'AI & Automation': 'building-with-ai',
  'E-Commerce & DTC': 'ecommerce-marketing',
  'Marketing & Growth': 'ecommerce-marketing',
  'Leadership & Career': 'career-leadership'
};

function getISOWeek(d) {
  const date = new Date(d);
  date.setHours(0, 0, 0, 0);
  date.setDate(date.getDate() + 3 - (date.getDay() + 6) % 7);
  const week1 = new Date(date.getFullYear(), 0, 4);
  const weekNum = 1 + Math.round(((date - week1) / 86400000 - 3 + (week1.getDay() + 6) % 7) / 7);
  return `${date.getFullYear()}-W${String(weekNum).padStart(2, '0')}`;
}

const DAY_TO_NUM = { Monday: 1, Tuesday: 2, Wednesday: 3, Thursday: 4 };

// Scan existing briefs — store full metadata for displacement detection
const existingBriefData = [];
try {
  const files = fs.readdirSync(briefsDir).filter(f => f.endsWith('.md'));
  for (const file of files) {
    const content = fs.readFileSync(`${briefsDir}/${file}`, 'utf8');
    const fmMatch = content.match(/^---\n([\s\S]*?)\n---/);
    if (fmMatch) {
      const fm = fmMatch[1];
      const sprintMatch = fm.match(/^sprint:\s*(.+)$/m);
      const pieceMatch = fm.match(/^piece_id:\s*(.+)$/m);
      const topicMatch = fm.match(/^topic:\s*(.+)$/m);
      const statusMatch = fm.match(/^status:\s*(.+)$/m);
      if (sprintMatch && pieceMatch) {
        existingBriefData.push({
          sprint: sprintMatch[1].trim(),
          piece_id: pieceMatch[1].trim(),
          topic: topicMatch ? topicMatch[1].trim() : 'unknown',
          status: statusMatch ? statusMatch[1].trim() : 'unknown',
          file
        });
      }
    }
  }
} catch (e) { /* ignore scan errors */ }

const usedSlots = new Set(existingBriefData.map(b => `${b.sprint}|${b.piece_id}`));
// Lookup: slotKey -> existing brief info for displacement detection
const slotOccupants = {};
for (const b of existingBriefData) {
  slotOccupants[`${b.sprint}|${b.piece_id}`] = b;
}

const assignments = [];
const urgencyAlerts = [];
const now = new Date();
const minDate = new Date(now);
minDate.setDate(minDate.getDate() + 2);

for (const brief of generatedBriefs) {
  const matchedPillars = brief.matchedPillars || [];
  const impactScore = brief.impactScore || 0;
  const strategyFit = brief.strategyFit || 0;
  const sourceCount = brief.sourceCount || (brief.matchedPillars || []).length;

  // --- URGENCY TIER ---
  let urgency = 'routine';
  if (impactScore > 40 || sourceCount >= 6) {
    urgency = 'breaking';
  } else if (impactScore >= 30 && strategyFit >= 8) {
    urgency = 'high-signal';
  }

  // Determine pillar
  let pillarId = null;
  if (brief.route === 'essay') {
    pillarId = 'pillar-four-essays';
  } else {
    for (const mp of matchedPillars) {
      if (PILLAR_MAP[mp]) {
        pillarId = PILLAR_MAP[mp];
        break;
      }
    }
  }

  if (!pillarId) continue;

  const pillar = pillars.find(p => p.id === pillarId);
  if (!pillar) continue;

  const targetDayNum = DAY_TO_NUM[pillar.day];
  if (targetDayNum === undefined) continue;

  // Find next occurrence of pillar's day >= minDate
  let scheduled = new Date(minDate);
  while (scheduled.getDay() !== targetDayNum) {
    scheduled.setDate(scheduled.getDate() + 1);
  }

  let sprint = getISOWeek(scheduled);
  let weekNum = sprint.split('-W')[1];
  let pieceId = `W${weekNum}-${String(pillar.day_index).padStart(2, '0')}`;
  let slotKey = `${sprint}|${pieceId}`;

  // Track what's in the nearest slot BEFORE bumping (for displacement alert)
  const nearestSlotOccupant = slotOccupants[slotKey] || null;

  // If slot taken, advance to next week
  let maxRetries = 4;
  let wasBumped = false;
  while (usedSlots.has(slotKey) && maxRetries > 0) {
    wasBumped = true;
    scheduled.setDate(scheduled.getDate() + 7);
    sprint = getISOWeek(scheduled);
    weekNum = sprint.split('-W')[1];
    pieceId = `W${weekNum}-${String(pillar.day_index).padStart(2, '0')}`;
    slotKey = `${sprint}|${pieceId}`;
    maxRetries--;
  }

  usedSlots.add(slotKey);

  // Format scheduled datetime
  const postTime = pillar.post_time || '08:30';
  const year = scheduled.getFullYear();
  const month = String(scheduled.getMonth() + 1).padStart(2, '0');
  const day = String(scheduled.getDate()).padStart(2, '0');
  const scheduledISO = `${year}-${month}-${day}T${postTime}:00-05:00`;

  // Update brief file on disk — inject sprint fields + urgency into frontmatter
  const briefPath = brief.path;
  try {
    let content = fs.readFileSync(briefPath, 'utf8');
    const fmEnd = content.indexOf('---', 4);
    if (fmEnd > 0) {
      const before = content.substring(0, fmEnd);
      const after = content.substring(fmEnd);
      let sprintFields = `sprint: ${sprint}\npiece_id: ${pieceId}\npillar: ${pillar.name}\nscheduled: ${scheduledISO}\n`;
      if (urgency !== 'routine') {
        sprintFields += `urgency: ${urgency}\n`;
      }
      content = before + sprintFields + after;
      fs.writeFileSync(briefPath, content, 'utf8');
    }
  } catch (e) { /* skip file write errors */ }

  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
  const assignment = {
    pieceId,
    day: dayNames[scheduled.getDay()],
    pillarName: pillar.name,
    topic: brief.topic,
    route: brief.route,
    filename: brief.filename,
    sprint,
    scheduled: scheduledISO,
    briefPath,
    urgency,
    impactScore,
    strategyFit
  };
  assignments.push(assignment);

  // --- URGENCY ALERTS ---
  if (urgency === 'high-signal' || urgency === 'breaking') {
    const alert = {
      urgency,
      topic: brief.topic,
      impactScore,
      strategyFit,
      sourceCount,
      assignedSlot: pieceId + ' (' + dayNames[scheduled.getDay()] + ')',
      assignedSprint: sprint
    };
    if (wasBumped && nearestSlotOccupant) {
      alert.displacedTo = 'next week (slot was taken)';
      alert.occupant = {
        topic: nearestSlotOccupant.topic,
        piece_id: nearestSlotOccupant.piece_id,
        status: nearestSlotOccupant.status,
        file: nearestSlotOccupant.file
      };
      alert.recommendation = urgency === 'breaking'
        ? 'Consider bumping "' + nearestSlotOccupant.topic + '" (' + nearestSlotOccupant.piece_id + ') to run this instead — timeliness may outweigh the queued piece.'
        : 'Slot taken by "' + nearestSlotOccupant.topic + '" — this was pushed to next week. Review if swap is warranted.';
    } else if (wasBumped) {
      alert.displacedTo = 'next week (slot was taken)';
      alert.recommendation = urgency === 'breaking'
        ? 'Pushed to next week but this is breaking news — consider manual override to publish sooner.'
        : 'Pushed to next week. Monitor if topic stays relevant.';
    } else {
      alert.recommendation = urgency === 'breaking'
        ? 'Slot was open — scheduled normally, but consider if this warrants same-day or next-day posting instead of waiting.'
        : 'Scheduled normally. High-signal — prioritize quality in production.';
    }
    urgencyAlerts.push(alert);
  }
}

return [{ json: { ...data, sprintAssignments: assignments, sprintAssignedCount: assignments.length, urgencyAlerts } }];
